// Sanitize all text fields from the webhook body AND validate required fields.
//
// SANITIZATION: signal_summaries (and other fields) can contain double quotes
// from G2 reviews, em-dashes from earnings statements, and newlines — all of
// which corrupt the JSON body string in the OpenRouter HTTP node when interpolated
// directly via n8n expressions. Strategy: replace double quotes with single quotes
// (semantically safe for AI prompts), collapse newlines, trim whitespace.
//
// VALIDATION: Email generation is blocked entirely if any of these are missing:
//   Company Name, Buyer Name, Buyer Title, Buyer Email, Tier
// Tier must also be 'Tier 1' or 'Tier 2' — Tier 3 and Discard are not emailed.
// A row that fails validation returns __skip: true so the downstream IF node
// routes it to the 'Mark Missing Buyer Data' Sheets node instead of OpenRouter.
// This prevents 'Hi ,' emails and ensures every sent email is fully personalized.

const body = $input.first().json.body;

function sanitize(val) {
  if (val === null || val === undefined) return '';
  return String(val)
    .replace(/"/g, "'")
    .replace(/\r?\n/g, ' ')
    .trim();
}

const cleaned = {
  buyer_name:       sanitize(body.buyer_name),
  buyer_title:      sanitize(body.buyer_title),
  company_name:     sanitize(body.company_name),
  company_domain:   sanitize(body.company_domain),
  buyer_email:      sanitize(body.buyer_email),
  funding_stage:    sanitize(body.funding_stage),
  employee_count:   body.employee_count ?? '',
  estimated_arr:    sanitize(body.estimated_arr),
  cs_headcount:     body.cs_headcount ?? '',
  tech_stack:       sanitize(body.tech_stack),
  total_score:      body.total_score ?? 0,
  tier:             sanitize(body.tier),
  signal_types:     sanitize(body.signal_types),
  signal_summaries: sanitize(body.signal_summaries)
};

// Validate all five required fields
const required = {
  'Company Name': cleaned.company_name,
  'Buyer Name':   cleaned.buyer_name,
  'Buyer Title':  cleaned.buyer_title,
  'Buyer Email':  cleaned.buyer_email,
  'Tier':         cleaned.tier
};

const missing = Object.entries(required)
  .filter(([_, v]) => !v)
  .map(([k]) => k);

const validTier = ['Tier 1', 'Tier 2'].includes(cleaned.tier);

if (missing.length > 0 || !validTier) {
  const reason = missing.length > 0
    ? `Missing required fields: ${missing.join(', ')}`
    : `Tier '${cleaned.tier}' is not eligible (must be Tier 1 or Tier 2)`;
  return [{
    json: {
      __skip: true,
      company_domain: cleaned.company_domain,
      reason
    }
  }];
}

return [{ json: cleaned }];

// Extract the generated email text from OpenRouter response
// and combine with account data for writing to Review Queue.
//
// Account data is read from the Webhook node (original, pre-sanitization) so
// fields like buyer_email are preserved exactly as received from WF4.
//
// total_score uses ?? (nullish coalescing) instead of || so that a score of 0
// is written as 0, not as an empty string. The || operator treats 0 as falsy.

const response    = $input.first().json;
const emailText   = response?.choices?.[0]?.message?.content || 'EMAIL GENERATION FAILED — check OpenRouter';
const accountData = $('Webhook — Generate Email').first().json.body;

return [{
  json: {
    'Date Added':      new Date().toISOString().split('T')[0],
    'Company Domain':  accountData.company_domain  || '',
    'Company Name':    accountData.company_name   || '',
    'Buyer Name':      accountData.buyer_name     || '',
    'Buyer Title':     accountData.buyer_title    || '',
    'Buyer Email':     accountData.buyer_email    || '',
    'Tier':            accountData.tier           || '',
    'Total Score':     accountData.total_score    ?? '',
    'Signal Summary':  accountData.signal_summaries || '',
    'Generated Email': emailText.trim(),
    'Your Action':     '',
    'Your Notes':      '',
    'Send Date':       '',
    'Reply Date':      '',
    'Outcome':         ''
  }
}];
